DROP TABLE IF EXISTS `items_menu`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `items_menu` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `categoria_id` int(11) NOT NULL,
  `nombre` varchar(100) NOT NULL,
  `descripcion` text DEFAULT NULL,
  `precio_base` decimal(10,2) NOT NULL,
  `precio_promocional` decimal(10,2) DEFAULT NULL,
  `disponible` tinyint(1) DEFAULT 1,
  `destacado` tinyint(1) DEFAULT 0,
  `calorias` int(11) DEFAULT NULL,
  `tiempo_preparacion` int(11) DEFAULT NULL COMMENT 'Tiempo en minutos',
  `imagen_url` varchar(500) DEFAULT NULL,
  `ingredientes` text DEFAULT NULL,
  `instrucciones_especiales` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_items_menu_categoria` (`categoria_id`),
  KEY `idx_items_menu_disponible` (`disponible`),
  CONSTRAINT `items_menu_ibfk_1` FOREIGN KEY (`categoria_id`) REFERENCES `categorias_menu` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=346 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
